mapper.insert:
insert into user (openid, name, phone, sex, id_number, avatar, create_time)
values (#{user.openid}, #{user.name}, #{user.phone}, #{user.sex}, #{user.idNumber}, #{user.avatar},
        #{user.createTime});

mapper.select:
select count(*)
from user

    and create_time >= #{begin}
    and create_time <= #{end}
